164â†’//see if a point in inside a face by projecting into 2d
165â†’uint32_t check_point_to_face(vms_vector *checkp, side *s,int facenum,int nv,int *vertex_list)
166â†’{
167â†’	vms_vector_array *checkp_array;
168â†’	vms_vector_array norm;
169â†’	vms_vector t;
170â†’	int biggest;
171â†’///
172â†’	int i,j,edge;
173â†’	uint32_t edgemask;
174â†’	fix check_i,check_j;
175â†’	vms_vector_array *v0,*v1;
176â†’
177â†’	#ifdef COMPACT_SEGS
178â†’		get_side_normal(sp, s-sp->sides, facenum, (vms_vector *)&norm );
179â†’	#else
180â†’		memcpy( &norm, &s->normals[facenum], sizeof(vms_vector_array));
181â†’	#endif
182â†’	checkp_array = (vms_vector_array *)checkp;
183â†’
184â†’	//now do 2d check to see if point is in side
185â†’
186â†’	//project polygon onto plane by finding largest component of normal
187â†’	t.x = labs(norm.xyz[0]); t.y = labs(norm.xyz[1]); t.z = labs(norm.xyz[2]);
188â†’
189â†’	if (t.x > t.y) if (t.x > t.z) biggest=0; else biggest=2;
190â†’	else if (t.y > t.z) biggest=1; else biggest=2;
191â†’
192â†’	if (norm.xyz[biggest] > 0) {
193â†’		i = ij_table[biggest][0];
194â†’		j = ij_table[biggest][1];
195â†’	}
196â†’	else {
197â†’		i = ij_table[biggest][1];
198â†’		j = ij_table[biggest][0];
199â†’	}
200â†’
201â†’	//now do the 2d problem in the i,j plane
202â†’
203â†’	check_i = checkp_array->xyz[i];
204â†’	check_j = checkp_array->xyz[j];
205â†’
206â†’	for (edge=edgemask=0;edge<nv;edge++) 
207â†’	{
208â†’		vec2d edgevec,checkvec;
209â†’		fix d;
210â†’
211â†’		v0 = (vms_vector_array *)&Vertices[vertex_list[facenum*3+edge]];
212â†’		v1 = (vms_vector_array *)&Vertices[vertex_list[facenum*3+((edge+1)%nv)]];
213â†’
214â†’		edgevec.i = v1->xyz[i] - v0->xyz[i];
215â†’		edgevec.j = v1->xyz[j] - v0->xyz[j];
216â†’
217â†’		checkvec.i = check_i - v0->xyz[i];
218â†’		checkvec.j = check_j - v0->xyz[j];
219â†’
220â†’		d = fixmul(checkvec.i,edgevec.j) - fixmul(checkvec.j,edgevec.i);
221â†’
222â†’		if (d < 0)              		//we are outside of triangle
223â†’			edgemask |= (1<<edge);
224â†’	}
225â†’
226â†’	return edgemask;
227â†’
228â†’}
