232â†’int check_sphere_to_face(vms_vector *pnt, side *s,int facenum,int nv,fix rad,int *vertex_list)
233â†’{
234â†’	vms_vector checkp=*pnt;
235â†’	uint32_t edgemask;
236â†’
237â†’	//now do 2d check to see if point is in side
238â†’
239â†’	edgemask = check_point_to_face(pnt,s,facenum,nv,vertex_list);
240â†’
241â†’	//we've gone through all the sides, are we inside?
242â†’
243â†’	if (edgemask == 0)
244â†’		return IT_FACE;
245â†’	else {
246â†’		vms_vector edgevec,checkvec;            //this time, real 3d vectors
247â†’		vms_vector closest_point;
248â†’		fix edgelen,d,dist;
249â†’		vms_vector *v0,*v1;
250â†’		int itype;
251â†’		int edgenum;
252â†’
253â†’		//get verts for edge we're behind
254â†’
255â†’		for (edgenum=0;!(edgemask&1);(edgemask>>=1),edgenum++);
256â†’
257â†’		v0 = &Vertices[vertex_list[facenum*3+edgenum]];
258â†’		v1 = &Vertices[vertex_list[facenum*3+((edgenum+1)%nv)]];
259â†’
260â†’		//check if we are touching an edge or point
261â†’
262â†’		vm_vec_sub(&checkvec,&checkp,v0);
263â†’		edgelen = vm_vec_normalized_dir(&edgevec,v1,v0);
264â†’		
265â†’		//find point dist from planes of ends of edge
266â†’
267â†’		d = vm_vec_dot(&edgevec,&checkvec);
268â†’
269â†’		if (d+rad < 0) return IT_NONE;                  //too far behind start point
270â†’
271â†’		if (d-rad > edgelen) return IT_NONE;    //too far part end point
272â†’
273â†’		//find closest point on edge to check point
274â†’
275â†’		itype = IT_POINT;
276â†’
277â†’		if (d < 0) closest_point = *v0;
278â†’		else if (d > edgelen) closest_point = *v1;
279â†’		else {
280â†’			itype = IT_EDGE;
281â†’
282â†’			//vm_vec_scale(&edgevec,d);
283â†’			//vm_vec_add(&closest_point,v0,&edgevec);
284â†’
285â†’			vm_vec_scale_add(&closest_point,v0,&edgevec,d);
286â†’		}
287â†’
288â†’		dist = vm_vec_dist(&checkp,&closest_point);
289â†’
290â†’		if (dist <= rad)
291â†’			return (itype==IT_POINT)?IT_NONE:itype;
292â†’		else
293â†’			return IT_NONE;
294â†’	}
295â†’
296â†’
297â†’}
